  let personas=$state.raw<Persona[]>([]),activePersona=$state.raw<Persona>(emptyPersona()),personaBound=$state(false),boundPersonaId=$state<string|null>(null),profile=$state.raw<CardRuntimeProfile|null>(null),passport=$state.raw<CardPassport|null>(null),firstMessage=$state(''),cards=$state.raw<Array<CardLibraryMeta&{ephemeral?:boolean}>>([]),presets=$state.raw<PromptPreset[]>([]),activePreset=$state.raw<PromptPreset>(defaultCardPreset()),activeProjectId=$state<string|null>(null),chatIndex=$state.raw<ChatIndex>({contract:'simbot-chat-index/0.1',projectId:'',chats:[],activeChatId:null});
