  function readSettings():Settings{const slot=():AuxSetting=>({provider:'openai',model:'gpt-4.1-mini',apiKey:''}),base:Settings={provider:'openai',endpoint:'',location:'',model:'gpt-4.1-mini',apiKey:'',voyageKey:'',auxEnabled:false,auxSlots:{translation:slot(),emotion:slot(),memory:slot()}};try{const raw=JSON.parse(localStorage.getItem('simbot.llm')??'null') as Partial<Settings>|null;if(!raw)return base;const auxSlots={...base.auxSlots,...(raw.auxSlots??{})};if(!raw.provider)return{...base,...raw,auxSlots,provider:'custom'};return{...base,...raw,auxSlots};}catch{return base;}}
  function provider():ModelProvider{return settings.apiKey.trim()?createProvider(settings):{async complete(){return{text:'LLM 설정에서 프로바이더, API 키와 모델을 입력하면 실제 대화를 시작할 수 있습니다.',events:[]};}};}
  async function changeProvider(value:ProviderId){settings.provider=value;models=catalogFor(value);if(models.length&&!models.some(item=>item.id===settings.model))settings.model=models[0]!.id;await refreshModels();}
  async function refreshModels(){if(!settings.apiKey.trim()){models=catalogFor(settings.provider);return;}models=await fetchModels(settings);}
  function auxConfig():AuxConfig{const slots=Object.fromEntries(Object.entries(settings.auxSlots).map(([name,value])=>[name,{provider:value.provider,model:value.model,apiKey:value.apiKey.trim()||settings.apiKey,...(value.provider==='custom'&&settings.endpoint?{endpoint:settings.endpoint}:{})}])) as AuxConfig['slots'];return{enabled:settings.auxEnabled,slots};}
  function makeSession(value:ProjectRuntime,id:string,cardProfile:CardRuntimeProfile|null,manifest:Record<string,unknown>|null){const content=(manifest?.content??value.project.content??{})as Record<string,unknown>,manifestPersonas=((manifest?.personas as Record<string,unknown>|undefined)?.library??[])as Persona[],projectPresets=((manifest?.prompts as Record<string,unknown>|undefined)?.presets??[])as PromptPreset[],character=((content.characters??[])as Record<string,unknown>[])[0]??{name:'Guide'},card=cardProfile?.card??{name:String(character.name??'Character'),description:String(character.description??'')};return new PlaySession({id,runtime:value,provider:provider(),aux:auxConfig(),preset:projectPresets[0]??(cardProfile?activePreset:enginePreset()),persona:cardProfile?activePersona:(manifestPersonas[0]??null),maxContext:settings.maxContext,card,loreEntries:(content.lorebooks??[])as unknown[],repository,...(cardProfile?{tagTranslator:translateYspTags,regexScripts:cardProfile.regexScripts,defaultVariables:cardProfile.defaultVariables}:{}),...(settings.voyageKey?{embeddingProvider:createVoyageProvider({apiKey:settings.voyageKey})}:{})});}
  async function runCompiler(){const parsed=currentParsed??(activeProjectId?await library?.loadCard(activeProjectId):null);if(!parsed||!settings.apiKey.trim())return;compiling=true;controller=new AbortController();try{compileReview=await compileCard({parsed,provider:createProvider(settings),signal:controller.signal});error='';}catch(reason){error=reason instanceof Error?reason.message:String(reason);}finally{compiling=false;controller=null;}}
