  async function openSimPack(bytes:Uint8Array){const project=unpackSimPack(bytes),manifest=project.manifest as unknown as Record<string,unknown>;legacy=true;currentManifest=manifest;profile=null;passport=null;firstMessage='';installPortraits(manifest,project.files);runtime=new ProjectRuntime(runtimeFromManifest(manifest));session=makeSession(runtime,`${runtime.project.projectId}:local`,null,manifest);const saved=await repository.get(session.id);if(saved)session.restore(saved.payload);version+=1;}
