  async function removeCard(id:string){const store=new ChatStore(repository as unknown as SessionRepository<ChatIndex>,id),index=await store.list();for(const chat of index.chats)await store.remove(chat.chatId);await repository.delete(`${id}:chatindex`);await library?.removeCard(id);cards=cards.filter(c=>c.projectId!==id);if(activeProjectId===id){profile=null;passport=null;session=null;activeProjectId=null;}}
  async function send(text:string){if(!session||!chatStore||!chatIndex.activeChatId)return;busy=true;controller=new AbortController();try{await session.send(text,controller.signal);await chatStore.touch(chatIndex.activeChatId,session.turn);chatIndex=await chatStore.list();version+=1;}catch(e){if(!controller.signal.aborted)error=e instanceof Error?e.message:String(e);}finally{busy=false;controller=null;}}
  function stop(){controller?.abort();}
