  async function redo(){if(!session)return;await session.redoTurn();if(chatStore&&chatIndex.activeChatId)await chatStore.touch(chatIndex.activeChatId,session.turn);chatIndex=chatStore?await chatStore.list():chatIndex;version+=1;}
  function changed(){version+=1;}
  async function reloadPersonas(id?:string){if(!personaLibrary)return;const data=await personaLibrary.list();personas=data.personas;activePersona=personas.find(p=>p.id===(id??data.index.activeId))??personas[0]??emptyPersona();session?.setPersona(activePersona);version+=1;}
  async function selectPersona(id:string){await personaLibrary?.setActive(id);if(personaBound&&profile)await personaLibrary?.bind(profile.project.projectId,id);await reloadPersonas(id);}
  async function savePersona(p:Persona){await personaLibrary?.save(p);await reloadPersonas(p.id);}
  async function removePersona(){if(personas.length<=1)return;await personaLibrary?.remove(activePersona.id);await reloadPersonas();}
