  async function removePreset(){if(presets.length<=1||!confirm('이 프리셋을 삭제할까요?'))return;await presetLibrary?.remove(activePreset.id);await reloadPresets();}
  async function importPresetFile(file:File){try{const imported=importRisuPreset(JSON.parse(await file.text()));await presetLibrary?.save(imported.preset);if(imported.provider.temperature!=null)settings.temperature=imported.provider.temperature;if(imported.provider.maxTokens!=null)settings.maxTokens=imported.provider.maxTokens;await reloadPresets(imported.preset.id);if(imported.unsupported.length)error=`미지원 항목 ${imported.unsupported.length}개를 비활성 보존했습니다.`;}catch(reason){error=reason instanceof Error?reason.message:String(reason);}}
  function exportPreset(){const blob=new Blob([JSON.stringify(activePreset,null,2)],{type:'application/json'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`${activePreset.name}.json`;a.click();URL.revokeObjectURL(url);}
  // 세션 재생성 대신 provider만 교체 — 재생성하면 런타임 전용인 체크포인트·대안이 유실된다(감사 #11).
  function numberSetting(key:keyof ProviderConfig,value:string){const number=value.trim()===''?undefined:Number(value);if(number===undefined||Number.isFinite(number))(settings as unknown as Record<string,unknown>)[key]=number;}
  function supports(key:keyof ProviderConfig){if(key==='temperature'||key==='maxTokens'||key==='maxContext'||key==='topP')return true;if(key==='topK')return settings.provider==='anthropic'||settings.provider==='google'||settings.provider==='vertex';if(key==='frequencyPenalty'||key==='presencePenalty')return !['anthropic','google','vertex'].includes(settings.provider);if(key==='seed')return settings.provider!=='anthropic';return false;}
  function saveSettings(){localStorage.setItem('simbot.llm',JSON.stringify(settings));showSettings=false;if(session){session.setProvider(provider());session.setAux(auxConfig());session.setMaxContext(settings.maxContext);session.setEmbeddingProvider(settings.voyageKey?createVoyageProvider({apiKey:settings.voyageKey}):undefined);version+=1;}}
  function clearPortraits(){for(const url of Object.values(portraitUrls))URL.revokeObjectURL(url);portraitUrls={};}
  function installPortraits(manifest:Record<string,unknown>,files:Record<string,Uint8Array>){clearPortraits();for(const raw of (manifest.assets??[]) as Array<Record<string,unknown>>){const blob=raw.blob as Record<string,unknown>|null,path=String(blob?.path??''),bytes=files[path],mime=String(blob?.mime??'');if(bytes&&mime.startsWith('image/'))portraitUrls.default=URL.createObjectURL(new Blob([Uint8Array.from(bytes)],{type:mime}));}}
  function installCardPortraits(assets:CardAsset[]){setDisplayAssets(assets);clearPortraits();for(const asset of assets){if(!asset.bytes||!asset.mime.startsWith('image/'))continue;const url=URL.createObjectURL(new Blob([Uint8Array.from(asset.bytes)],{type:asset.mime})),key=normalize(asset.name||asset.type);portraitUrls[`asset:${key}`]=url;if(!portraitUrls.default)portraitUrls.default=url;}}
  function portraitFor(id:string,emotion?:string){return portraitUrls[`asset:${normalize(id)}-${normalize(emotion??'default')}`]??portraitUrls[`asset:${normalize(id)}`]??portraitUrls.default??null;}
  function normalize(v:string){return v.normalize('NFKC').toLowerCase().replace(/[\s./\\]+/g,'-');}
  function demo(){return new ProjectRuntime({projectId:'demo',schema:{initialState:{day:1}},screens:[{id:'play',title:'플레이',layout:'stage-chat-sidebar',regions:{main:[{widget:'chat'}]}}],navigation:[{id:'play',screenId:'play',label:'플레이'}],content:{},featureToggles:{},moduleIds:[]});}
</script>
<svelte:window onresize={()=>compact=innerWidth<1000}/><input class="hidden" bind:this={fileInput} type="file" accept=".simpack,.charx,.png,.json" onchange={load}/>
{#if profile}<section class="compiler-bar"><button disabled={!settings.apiKey.trim()||compiling} onclick={()=>void runCompiler()}>{compiling?'엔진 컴파일 중…':'엔진 컴파일'}</button>{#if !settings.apiKey.trim()}<span>LLM 설정에서 API 키를 입력하면 사용할 수 있습니다.</span>{:else}<span>{passport?.mode==='full-sim'?'승인된 컴파일을 사용 중':'현재는 태그 전용 일반 채팅 모드입니다.'}</span>{/if}</section>{/if}
{#if compileReview}<div class="compile-review"><div><h2>엔진 컴파일 검수</h2><p>스키마: {String((compileReview.schema.meta as Record<string,unknown>|undefined)?.title??(compileReview.schema.meta as Record<string,unknown>|undefined)?.id??'이름 없음')} · 모듈 {compileReview.moduleIds.length}개</p><h3>숫자 교정 로그</h3>{#if compileReview.patches.length}<ul>{#each compileReview.patches as patch}<li><code>{patch.path}</code>: {JSON.stringify(patch.from)} → {JSON.stringify(patch.to)} <small>({patch.source})</small></li>{/each}</ul>{:else}<p>교정된 숫자가 없습니다.</p>{/if}<h3>진단·미지원</h3><ul>{#each compileReview.warnings as warning}<li>{warning}</li>{/each}{#each compileReview.diagnosis.compilerCoverage.omitted as item}<li>컴파일 입력 제외: {item.name} ({item.chars}자)</li>{/each}</ul><footer><button onclick={()=>compileReview=null}>취소</button><button class="approve" onclick={()=>void approveCompilation()}>승인하고 적용</button></footer></div></div>{/if}
{#if legacy}<div class="legacy"><button onclick={()=>fileInput.click()}>카드 또는 SimPack 열기</button>{#if session}<ScreenRenderer {runtime} {version} {session} {portraitFor}/>{/if}</div>
{:else if profile&&passport&&session}<div class="shell"><MobileShell cardName={profile.card.name} {cards} index={chatIndex} activeId={activeProjectId} onadd={()=>fileInput.click()} oncard={(id)=>void activateCard(id)} onchat={(id)=>void activateChat(id)} onsettings={()=>showSettings=true}/><AvatarStrip {cards} activeId={activeProjectId} avatarFor={(id)=>id===activeProjectId?portraitFor(profile?.card.name??id):null} onadd={()=>fileInput.click()} onselect={(id)=>void activateCard(id)} onremove={(id)=>void removeCard(id)} onsettings={()=>showSettings=true}/><SidePanel {profile} {passport} index={chatIndex} {session} {version} {bindingUi} open={sideOpen} oncreate={()=>void createChat()} onselect={(id)=>void activateChat(id)} onrename={(id)=>void renameChat(id)} onremove={(id)=>void removeChat(id)} onundo={()=>void undo()} onredo={()=>void redo()}/><main><MessageList {session} {version} greetings={profile.greetings} cardName={profile.card.name} userName={activePersona.name} model={settings.model} waiting={busy} {portraitFor} onchange={changed} onerror={(m)=>error=m}/><InputBar {busy} onsend={send} onstop={stop}/></main></div>
{:else if booting}<div class="empty"><p>저장소를 여는 중…</p></div>
{:else}<div class="shell"><MobileShell {cards} index={chatIndex} activeId={activeProjectId} onadd={()=>fileInput.click()} oncard={(id)=>void activateCard(id)} onchat={(id)=>void activateChat(id)} onsettings={()=>showSettings=true}/><AvatarStrip {cards} activeId={activeProjectId} avatarFor={(id)=>id===activeProjectId?portraitFor(profile?.card.name??id):null} onadd={()=>fileInput.click()} onselect={(id)=>void activateCard(id)} onremove={(id)=>void removeCard(id)} onsettings={()=>showSettings=true}/><main class="blank"><div><h1>럭키★시뮬레이터</h1><p>리스 시뮬봇 카드를 그대로 가져와, 수백 턴을 굴려도 상태가 어긋나지 않는 곳.</p><button class="primary" onclick={()=>fileInput.click()}><Icon name="plus"/> 카드 가져오기 (.charx · .png)</button><button class="link" onclick={()=>onnavigate?.('editor')}>제작 편집기</button></div></main></div>
{/if}
{#if showSettings}<SettingsPanel {settings} {providerChoices} {models} {promptUi} {personaUi} onsave={saveSettings} onclose={()=>showSettings=false} onprovider={(id)=>void changeProvider(id)} onmodels={()=>void refreshModels()} {numberSetting} {supports}/>{/if}{#if error}<div class="error">{error}<button onclick={()=>{error='';}}>닫기</button></div>{/if}
<style>.hidden{position:fixed;width:1px;height:1px;opacity:0}.shell{display:flex;width:100%;height:100dvh;overflow:hidden;background:#111318;color:#e6e8ee}.shell main{position:relative;flex:1;min-width:0;height:100dvh;overflow-y:auto}.shell main :global(form){position:sticky;bottom:0}.legacy{padding:20px}.blank{display:grid;place-items:center;text-align:center;padding:24px}.blank>div{display:grid;justify-items:center;gap:14px;max-width:36ch}.blank h1{margin:0;font:600 30px/1.2 Georgia,'Noto Serif KR',serif}.blank p{margin:0;color:#9aa1ae;line-height:1.6}.blank button{display:flex;align-items:center;gap:7px;padding:10px 14px;border:1px solid #414650;border-radius:8px;background:#222630;color:#eee;cursor:pointer}.blank .primary{border-color:#6c98f4;color:#cfe0ff}.blank .link{border:0;background:transparent;color:#7d8596;font-size:12px}.legacy>button{padding:10px 14px;border:1px solid #414650;border-radius:8px;background:#222630;color:#eee}.empty{min-height:100dvh;display:grid;place-content:center;text-align:center;background:#111318;color:#eee}.error{position:fixed;right:16px;bottom:16px;z-index:60;background:#642f39;color:#fff;padding:10px 14px;border-radius:8px}.error button{border:0;background:transparent;color:#fff}@media(max-width:999px){.shell main{width:100%;padding-top:calc(56px + env(safe-area-inset-top));box-sizing:border-box}.shell main :global(form){padding-bottom:calc(18px + env(safe-area-inset-bottom));background:#111318}}</style>
